    if (tx < sx || ty < sy) {
        return -1;
    }
    if (tx == sx && ty == sy) {
        return 0;
    }
    if (tx > ty) {
        long new_tx = tx - ty;
        if (new_tx < sx) {
            return -1;
        }
        long steps = solve(sx, sy, new_tx, ty);
        if (steps == -1) {
            return -1;
        }
        return steps + 1;
    } else if (ty > tx) {
        long new_ty = ty - tx;
        if (new_ty < sy) {
            return -1;
        }
        long steps = solve(sx, sy, tx, new_ty);
        if (steps == -1) {
            return -1;
        }
        return steps + 1;
    } else {
        return -1;
    }
}
```

